import { describe, it, expect } from 'vitest';
import { forkRaceFoldDeblur } from '../src/forkraceFoldDeblur';
import { deblurAnyImage } from '../src/deblur-any-image';

// Linear congruential generator with a fixed seed so the synthetic fixture
// is deterministic across test runs.
function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff - 0.5;
  };
}

// Small natural-looking fixture: radial Gaussian blob + sinusoidal ripple +
// low-amplitude noise. Same shape as other deblur tests in this dir.
function makeNaturalish(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h);
  const rand = lcg(seed);
  const cx = w / 2;
  const cy = h / 2;
  const scale = (Math.min(w, h) ** 2) / 16;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const dx = x - cx;
      const dy = y - cy;
      const radial = Math.exp(-(dx * dx + dy * dy) / scale);
      const ripple = 0.15 * Math.sin(x / 5) * Math.cos(y / 4);
      const noise = 0.05 * rand();
      let v = radial + ripple + noise;
      if (v < 0) v = 0;
      if (v > 1) v = 1;
      out[y * w + x] = v;
    }
  }
  return out;
}

const W = 64;
const H = 64;

function makeInput() {
  return {
    data: makeNaturalish(W, H, 42),
    width: W,
    height: H,
    channels: 1 as const,
  };
}

function rmse(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`rmse: length mismatch ${a.length} vs ${b.length}`);
  }
  let s = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i]! - b[i]!;
    s += d * d;
  }
  return Math.sqrt(s / a.length);
}

describe('forkRaceFoldDeblur', () => {
  it('single config passes through to the same recovered plane', async () => {
    const input = makeInput();
    const opts = { sigma: 2, method: 'wiener' as const };

    const direct = await deblurAnyImage(input, opts);
    const ensemble = await forkRaceFoldDeblur({
      input,
      configs: [{ label: 'wiener-2', options: opts }],
    });

    expect(ensemble.width).toBe(W);
    expect(ensemble.height).toBe(H);
    expect(ensemble.channels).toBe(1);
    expect(ensemble.fold.survivors).toBe(1);
    expect(ensemble.fold.rejected).toBe(0);
    expect(ensemble.candidates).toHaveLength(1);
    expect(ensemble.candidates[0]!.rank).toBe(0);
    // R=1, rank=0 → weight = 1 - min(0,1) + 1 = 2
    expect(ensemble.candidates[0]!.buleyWeight).toBe(2);

    // Single survivor, weighted average reduces to a divided-by-self copy.
    expect(rmse(ensemble.recovered, direct.recovered)).toBeLessThan(1e-4);
  });

  it('three configs ranked correctly and all survive', async () => {
    const input = makeInput();
    const ensemble = await forkRaceFoldDeblur({
      input,
      configs: [
        { label: 's1', options: { sigma: 1.0, method: 'wiener' } },
        { label: 's2', options: { sigma: 2.0, method: 'wiener' } },
        { label: 's4', options: { sigma: 4.0, method: 'wiener' } },
      ],
    });

    expect(ensemble.fold.survivors).toBe(3);
    expect(ensemble.fold.rejected).toBe(0);
    expect(ensemble.candidates).toHaveLength(3);

    // All three have rank ∈ {0,1,2} exactly once.
    const ranks = ensemble.candidates.map((c) => c.rank).sort();
    expect(ranks).toEqual([0, 1, 2]);

    // R=3 → buleyeanWeight(3, rank) ∈ {4, 3, 2}.
    const weightsByRank = new Map<number, number>();
    for (const c of ensemble.candidates) weightsByRank.set(c.rank, c.buleyWeight);
    expect(weightsByRank.get(0)).toBe(4);
    expect(weightsByRank.get(1)).toBe(3);
    expect(weightsByRank.get(2)).toBe(2);

    // Total weight = 4 + 3 + 2 = 9.
    expect(ensemble.fold.totalWeight).toBe(9);
  });

  it('low ceiling filters every candidate and throws no-survivors error', async () => {
    const input = makeInput();
    await expect(
      forkRaceFoldDeblur({
        input,
        configs: [
          { label: 'a', options: { sigma: 2 } },
          { label: 'b', options: { sigma: 3 } },
        ],
        // 0.5 is positive (passes the validator) but smaller than the
        // carrierBuley.score=1 produced by `composeWithFaceUnit` on a
        // single-face lift, so every candidate fails the ceiling filter
        // and the no-survivors path triggers.
        ceiling: 0.5,
      }),
    ).rejects.toThrow(/no candidates survived ceiling filter/);
  });

  it('empty configs throws RangeError', async () => {
    const input = makeInput();
    await expect(
      forkRaceFoldDeblur({ input, configs: [] }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('pixel-wise weighted average matches manual computation', async () => {
    const input = makeInput();

    // Run each config solo so we have ground-truth recovered planes to mix
    // by hand.
    const optsA = { sigma: 1.0, method: 'wiener' as const };
    const optsB = { sigma: 4.0, method: 'wiener' as const };

    const a = await deblurAnyImage(input, optsA);
    const b = await deblurAnyImage(input, optsB);

    const ensemble = await forkRaceFoldDeblur({
      input,
      configs: [
        { label: 'a', options: optsA },
        { label: 'b', options: optsB },
      ],
    });

    expect(ensemble.fold.survivors).toBe(2);

    const ca = ensemble.candidates.find((c) => c.label === 'a')!;
    const cb = ensemble.candidates.find((c) => c.label === 'b')!;
    const wa = ca.buleyWeight;
    const wb = cb.buleyWeight;
    const totalW = wa + wb;

    // Spot-check several pixels — center, off-center, a corner-ish point.
    const samplePixels = [
      Math.floor((H / 2) * W + W / 2),
      Math.floor((H / 4) * W + W / 4),
      Math.floor((H * 3) / 4) * W + Math.floor((W * 3) / 4),
      0,
      W * H - 1,
    ];
    for (const p of samplePixels) {
      const expected = (wa * a.recovered[p]! + wb * b.recovered[p]!) / totalW;
      expect(ensemble.recovered[p]).toBeCloseTo(expected, 5);
    }
  });

  it('heterogeneous methods (Wiener + Richardson-Lucy) both contribute', async () => {
    const input = makeInput();
    const ensemble = await forkRaceFoldDeblur({
      input,
      configs: [
        { label: 'wiener', options: { sigma: 2, method: 'wiener' } },
        {
          label: 'rl',
          options: { sigma: 2, method: 'richardson-lucy', iterations: 10 },
        },
      ],
    });

    expect(ensemble.fold.survivors).toBe(2);
    expect(ensemble.fold.rejected).toBe(0);
    expect(ensemble.candidates).toHaveLength(2);

    const methods = ensemble.candidates.map((c) => c.methodUsed).sort();
    expect(methods).toEqual(['richardson-lucy', 'wiener']);

    // Both got non-zero buley weights.
    for (const c of ensemble.candidates) {
      expect(c.buleyWeight).toBeGreaterThan(0);
      expect(c.rejectedByCeiling).toBe(false);
    }

    // Total weight = buleyeanWeight(2,0) + buleyeanWeight(2,1) = 3 + 2 = 5.
    expect(ensemble.fold.totalWeight).toBe(5);
  });

  it('applies invisible watermark once on folded output when enabled', async () => {
    const input = makeInput();
    const ensemble = await forkRaceFoldDeblur({
      input,
      configs: [{ label: 'w', options: { sigma: 2, method: 'wiener' } }],
      invisibleWatermark: {
        enabled: true,
        seed: 'ensemble-seed',
        payload: 'frf',
        strength: 0.015,
      },
    });
    expect(ensemble.invisibleWatermark?.id.length).toBeGreaterThan(0);
    expect(ensemble.invisibleWatermark?.mode).toBe('luma_spread');
    expect(ensemble.invisibleWatermark?.payloadBits).toBe(64);
  });
});
